         * Heaviest single-axle load in tonnes, if known.
         */axleLoadT: Double? = nil, 
        /**
         * Number of axles, if known.
         */axleCount: UInt32? = nil, 
        /**
         * Whether the vehicle carries dangerous goods at all.
         */hazmat: Bool = false, 
        /**
         * Declared ADR tunnel restriction code. `None` with `hazmat = true`
         * means "dangerous goods of unknown code" and is treated as code B
         * (most restrictive non-quantity code).
         */tunnelCode: AdrTunnelCode? = nil) {
        self.heightM = heightM
        self.widthM = widthM
        self.lengthM = lengthM
        self.grossWeightT = grossWeightT
        self.axleLoadT = axleLoadT
