/**
 * Guidance behaviour configuration, flattened for FFI.
 *
 * Maps onto Ferrostar's `NavigationControllerConfig`: a
 * distance-to-end-of-step advance condition, a static-threshold route
 * deviation tracker and course snapping.
 */
public struct GuidanceConfig: Equatable, Hashable {
    /**
     * Advance to the next step when the user is within this many metres
     * of the end of the current step.
     */
    public var stepAdvanceDistanceM: UInt16
    /**
     * Location fixes with worse horizontal accuracy than this (metres)
     * can neither advance a step nor flag a deviation.
     */
    public var minimumHorizontalAccuracyM: UInt16
    /**
     * The user is off route when further than this many metres from the
     * route line.
     */
    public var routeDeviationThresholdM: Double
    /**
     * Snap the reported course to the route line (`true`, recommended for
     * vehicular navigation) or report the raw course (`false`).
     */
    public var snapCourseToRoute: Bool
    /**
     * A waypoint is considered visited within this many metres.
     */
    public var waypointAdvanceRangeM: Double

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * Advance to the next step when the user is within this many metres
         * of the end of the current step.
         */stepAdvanceDistanceM: UInt16 = UInt16(20), 
        /**
         * Location fixes with worse horizontal accuracy than this (metres)
         * can neither advance a step nor flag a deviation.
         */minimumHorizontalAccuracyM: UInt16 = UInt16(25), 
        /**
         * The user is off route when further than this many metres from the
         * route line.
         */routeDeviationThresholdM: Double = Double(25.0), 
        /**
         * Snap the reported course to the route line (`true`, recommended for
         * vehicular navigation) or report the raw course (`false`).
         */snapCourseToRoute: Bool = true, 
        /**
         * A waypoint is considered visited within this many metres.
         */waypointAdvanceRangeM: Double = Double(100.0)) {
        self.stepAdvanceDistanceM = stepAdvanceDistanceM
        self.minimumHorizontalAccuracyM = minimumHorizontalAccuracyM
        self.routeDeviationThresholdM = routeDeviationThresholdM
        self.snapCourseToRoute = snapCourseToRoute
        self.waypointAdvanceRangeM = waypointAdvanceRangeM
    }

    

    
}

